import React, { useState, useEffect } from 'react';

// --- RENK PALETİ VE STİLLER ---
const colors = {
  butterYellow: '#FEFAE0',
  softPink: '#F8AD9D',
  softBeige: '#FAEDCD',
  softGreen: '#B5E48C',
  white: '#FFFFFF',
  text: '#6B705C'
};

// --- YARDIMCI FONKSİYON: Saniyeyi Saat Formatına Çevirir ---
const formatTime = (totalSeconds) => {
  const h = String(Math.floor(totalSeconds / 3600)).padStart(2, '0');
  const m = String(Math.floor((totalSeconds % 3600) / 60)).padStart(2, '0');
  const s = String(totalSeconds % 60).padStart(2, '0');
  return `${h}:${m}:${s}`;
};

const commonStyles = {
  container: { backgroundColor: colors.butterYellow, minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: 'sans-serif', padding: '20px' },
  card: { backgroundColor: colors.white, width: '100%', maxWidth: '650px', padding: '40px', borderRadius: '40px', boxShadow: '0 15px 30px rgba(0,0,0,0.05)', textAlign: 'center' },
  button: { width: '100%', padding: '15px', backgroundColor: colors.softPink, color: 'white', border: 'none', borderRadius: '15px', fontWeight: 'bold', cursor: 'pointer', marginTop: '20px', transition: '0.3s' },
  tag: { padding: '10px 15px', borderRadius: '12px', border: `1px solid ${colors.softBeige}`, cursor: 'pointer', fontSize: '14px', transition: '0.3s' }
};

// --- 1. SAYFA: GİRİŞ ---

const AuthPage = ({ onNext }) => {
  const [formData, setFormData] = useState({ username: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);

  const handleRegister = async () => {
    if (!formData.username || !formData.email || !formData.password) {
      return alert("Lütfen tüm alanları doldur 🌸");
    }
    setLoading(true);

    try {
      const response = await fetch('http://localhost:5001/api/auth/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      const data = await response.json();

      if (response.ok) {
        alert("Planly dünyasına hoş geldin! ✨");
        onNext();
      } else {
        alert(data.error);
      }
    } catch (error) {
      alert("Bağlantı hatası! Lütfen Docker terminalini kontrol et.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={commonStyles.container}>
      <div style={{ ...commonStyles.card, maxWidth: '450px' }}>
        <h1 style={{ color: colors.softPink, fontSize: '32px', marginBottom: '10px' }}>Planly 🌸</h1>
        <p style={{ color: '#A5A5A5', marginBottom: '25px' }}>Hesabını oluştur ve çalışmaya başla.</p>

        <input 
          type="text" placeholder="Kullanıcı Adı" 
          value={formData.username}
          onChange={(e) => setFormData({...formData, username: e.target.value})}
          style={authInputStyle}
        />
        <input 
          type="email" placeholder="E-posta" 
          value={formData.email}
          onChange={(e) => setFormData({...formData, email: e.target.value})}
          style={authInputStyle}
        />
        <input 
          type="password" placeholder="Şifre" 
          value={formData.password}
          onChange={(e) => setFormData({...formData, password: e.target.value})}
          style={authInputStyle}
        />

        <button 
          style={{ ...commonStyles.button, marginTop: '10px' }} 
          onClick={handleRegister}
          disabled={loading}
        >
          {loading ? "Hesabın Hazırlanıyor..." : "Üye Ol ✨"}
        </button>
      </div>
    </div>
  );
};

// Küçük bir stil yardımcısı
const authInputStyle = {
  width: '100%', padding: '15px', borderRadius: '15px', 
  border: `2px solid ${colors.softBeige}`, marginBottom: '12px', outline: 'none'
};




// --- 2. SAYFA: ONBOARDING (Ders ve Konu Seçimi) ---
const OnboardingPage = ({ onNext }) => {
  const [examsData, setExamsData] = useState([]); 
  const [currentStep, setCurrentStep] = useState('examSelection');
  const [selectedExam, setSelectedExam] = useState(null);
  const [selectedSubjects, setSelectedSubjects] = useState([]);
  const [selectedTopics, setSelectedTopics] = useState({});
  const [hours, setHours] = useState(4);
  const [isGenerating, setIsGenerating] = useState(false); // Yüklenme animasyonu için

  // --- VERİTABANINDAN ÇEKME (Akıllı Ayıklayıcı ile) ---
  useEffect(() => {
    fetch('http://localhost:5001/api/exams')
      .then(res => res.json())
      .then(data => {
        if (data.length > 0) {
          // Eğer MongoDB verileri "0, 1, 2" şeklinde tek dökümana tıkıştırdıysa:
          if (data[0] && data[0]["0"]) {
            const parsedData = Object.keys(data[0])
              .filter(key => !isNaN(key))
              .map(key => data[0][key]);
            setExamsData(parsedData);
          } else {
            // Normal dizi olarak geldiyse:
            setExamsData(data);
          }
        }
      })
      .catch(err => console.error("Veri çekme hatası:", err));
  }, []);

  const toggleSubject = (subName) => {
    setSelectedSubjects(prev => 
      prev.includes(subName) ? prev.filter(s => s !== subName) : [...prev, subName]
    );
  };

  const toggleTopic = (subName, topic) => {
    setSelectedTopics(prev => {
      const currentSubTopics = prev[subName] || [];
      const newSubTopics = currentSubTopics.includes(topic) 
        ? currentSubTopics.filter(t => t !== topic) 
        : [...currentSubTopics, topic];
      return { ...prev, [subName]: newSubTopics };
    });
  };

  // --- YAPAY ZEKAYA İSTEK ATMA ---
  const handleGenerateSchedule = async () => {
    setIsGenerating(true);
    try {
      const response = await fetch('http://localhost:5001/api/generate-schedule', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          exam: selectedExam.name,
          subjects: selectedSubjects,
          topics: selectedTopics,
          hours: hours
        })
      });

      const scheduleData = await response.json();
      onNext(scheduleData); // Üretilen programı App'e ve oradan 3. sayfaya gönder

    } catch (error) {
      console.error("Program üretilirken hata oluştu:", error);
      alert("Program üretilemedi. Backend ayarlarını veya API Key'i kontrol et! 🌸");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div style={commonStyles.container}>
      <div style={{ ...commonStyles.card }}>

        {/* ADIM 1: SINAV SEÇİMİ */}
        {currentStep === 'examSelection' && (
          <>
            <h2 style={{ color: colors.text, marginBottom: '20px' }}>Hedefini Seç ✨</h2>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
              {examsData.length > 0 ? examsData.map(exam => (
                <div key={exam.name} onClick={() => { setSelectedExam(exam); setCurrentStep('subjectSelection'); }} 
                     style={{ ...commonStyles.tag, padding: '25px', backgroundColor: 'white', fontWeight: 'bold', border: `1px solid ${colors.softBeige}` }}>
                  {exam.name}
                </div>
              )) : <p style={{ color: colors.text }}>Veriler yükleniyor... 🌸</p>}
            </div>
          </>
        )}

        {/* ADIM 2: DERS SEÇİMİ */}
        {currentStep === 'subjectSelection' && selectedExam && (
          <>
            <h2 style={{ color: colors.text }}>{selectedExam.name} Dersleri 📚</h2>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px', justifyContent: 'center', marginTop: '20px' }}>
              {selectedExam.subjects.map(sub => (
                <div key={sub.name} onClick={() => toggleSubject(sub.name)}
                     style={{ ...commonStyles.tag, backgroundColor: selectedSubjects.includes(sub.name) ? colors.softGreen : 'white', color: selectedSubjects.includes(sub.name) ? 'white' : colors.text }}>
                  {sub.name}
                </div>
              ))}
            </div>
            <button style={{...commonStyles.button, backgroundColor: selectedSubjects.length > 0 ? colors.softPink : '#ddd'}} disabled={selectedSubjects.length === 0} onClick={() => setCurrentStep('topicSelection')}>Konuları Seç →</button>
            <p onClick={() => setCurrentStep('examSelection')} style={{ marginTop: '15px', fontSize: '12px', cursor: 'pointer', color: '#aaa' }}>← Sınav Değiştir</p>
          </>
        )}

        {/* ADIM 3: KONU VE SAAT SEÇİMİ */}
        // OnboardingPage içindeki Takvim ve Saat Seçimi Kısmı
{currentStep === 'topicSelection' && selectedExam && (
  <>
    <h2 style={{ color: colors.text }}>Son Ayarlar 🗓️</h2>

    {/* KONU LİSTESİ (Mevcut kodun) */}
    <div style={{ textAlign: 'left', maxHeight: '250px', overflowY: 'auto', marginTop: '10px', padding: '10px', backgroundColor: '#f9f9f9', borderRadius: '15px' }}>
      {selectedExam.subjects.filter(s => selectedSubjects.includes(s.name)).map(sub => (
        <div key={sub.name} style={{ marginBottom: '10px' }}>
          <h4 style={{ color: colors.softPink, fontSize: '13px', margin: '5px 0' }}>{sub.name}</h4>
          <p style={{ fontSize: '11px', color: '#888' }}>{selectedTopics[sub.name]?.join(', ') || 'Konu seçilmedi'}</p>
        </div>
      ))}
    </div>

    {/* YENİ: TAKVİM (HEDEF TARİH) */}
    <div style={{ marginTop: '20px', textAlign: 'left' }}>
      <label style={{ fontWeight: 'bold', fontSize: '14px', color: colors.text, display: 'block', marginBottom: '8px' }}>
        Hedef Bitirme Tarihi 🏁
      </label>
      <input 
        type="date" 
        value={targetDate} 
        onChange={(e) => setTargetDate(e.target.value)}
        min={new Date().toISOString().split('T')[0]} // Geçmiş tarih seçilemesin
        style={{ 
          width: '100%', padding: '12px', borderRadius: '12px', 
          border: `2px solid ${colors.softBeige}`, outline: 'none', color: colors.text 
        }}
      />
    </div>

    {/* SAAT SEÇİMİ */}
    <div style={{ marginTop: '20px' }}>
      <p style={{ fontWeight: 'bold', fontSize: '14px', color: colors.text, margin: '5px 0' }}>
        Günlük Çalışma Kapasitesi: {hours} Saat
      </p>
      <input type="range" min="1" max="12" value={hours} onChange={(e) => setHours(e.target.value)} style={{ width: '100%', accentColor: colors.softPink }} />
    </div>

    <button 
      style={{ ...commonStyles.button, opacity: isGenerating ? 0.7 : 1 }} 
      onClick={handleGenerateSchedule}
      disabled={isGenerating}
    >
      {isGenerating ? "Yapay Zeka Takvimi Ayarlıyor... ⏳" : "Kişiselleştirilmiş Programı Üret ✨"}
    </button>
  </>
)}


      </div>
    </div>
  );
};

// --- 3. SAYFA: DASHBOARD (Takvim & Arkadaşlar) ---
// --- 3. SAYFA: DASHBOARD (Sadece Haftalık Plan - Sadeleşmiş) ---
const DashboardPage = ({ schedule, onBack, onGoToFriends }) => {
  const [completedTasks, setCompletedTasks] = useState({});

  const totalTasks = schedule ? schedule.reduce((acc, day) => acc + day.tasks.length, 0) : 0;
  const completedCount = Object.values(completedTasks).filter(val => val === true).length;
  const successRate = totalTasks > 0 ? Math.round((completedCount / totalTasks) * 100) : 0;


  const toggleTask = (day, task) => {
    const taskId = `${day}-${task}`;
    setCompletedTasks(prev => ({
      ...prev,
      [taskId]: !prev[taskId]
    }));
  };

  return (
    <div style={commonStyles.container}>
      <div style={{ ...commonStyles.card, maxWidth: '1200px', padding: '40px' }}>

        {/* ÜST PANEL: ANALİZ VE İLERLEME */}
        <div style={{ display: 'flex', gap: '20px', marginBottom: '30px', flexWrap: 'wrap' }}>

          {/* BAŞARI YÜZDESİ KARTI */}
          <div style={{ 
            flex: '1', 
            minWidth: '250px', 
            backgroundColor: colors.softGreen + '20', 
            padding: '25px', 
            borderRadius: '30px', 
            border: `2px solid ${colors.softGreen}`,
            textAlign: 'center'
          }}>
            <h3 style={{ color: colors.text, margin: '0 0 10px 0', fontSize: '16px' }}>Haftalık Başarı Oranı 📈</h3>
            <div style={{ fontSize: '48px', fontWeight: 'bold', color: colors.softGreen }}>%{successRate}</div>
            <div style={{ 
              width: '100%', 
              height: '10px', 
              backgroundColor: colors.white, 
              borderRadius: '5px', 
              marginTop: '15px',
              overflow: 'hidden' 
            }}>
              <div style={{ 
                width: `${successRate}%`, 
                height: '100%', 
                backgroundColor: colors.softGreen, 
                transition: 'width 0.5s ease-in-out' 
              }}></div>
            </div>
          </div>

          {/* DERS ANALİZ ÖZETİ */}
          <div style={{ 
            flex: '1', 
            minWidth: '250px', 
            backgroundColor: colors.softPink + '10', 
            padding: '25px', 
            borderRadius: '30px', 
            border: `2px solid ${colors.softPink}`,
            textAlign: 'left'
          }}>
            <h3 style={{ color: colors.text, margin: '0 0 15px 0', fontSize: '16px' }}>Ders Analiz Takibi 📑</h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <p style={{ margin: 0, color: colors.text, fontSize: '14px' }}>✅ Tamamlanan: <b>{completedCount}</b></p>
              <p style={{ margin: 0, color: colors.text, fontSize: '14px' }}>⏳ Kalan Görev: <b>{totalTasks - completedCount}</b></p>
              <p style={{ margin: 0, color: colors.text, fontSize: '14px' }}>🎯 Toplam Hedef: <b>{totalTasks}</b></p>
            </div>
          </div>

          {/* AKSİYON BUTONLARI */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', justifyContent: 'center' }}>
            <button 
              style={{ ...commonStyles.tag, backgroundColor: colors.softGreen, color: 'white', border: 'none', padding: '12px 25px', fontWeight: 'bold' }}
              onClick={onGoToFriends}
            >
              Canlı Odaya Gir 👩🏻‍💻
            </button>
            <button onClick={onBack} style={{ background: 'none', border: `1px solid ${colors.softBeige}`, color: '#aaa', cursor: 'pointer', padding: '10px', borderRadius: '12px' }}>
              ← Planı Düzenle
            </button>
          </div>
        </div>

        {/* HAFTALIK GÖREV KUTUCUKLARI (Artık Tüm Ekranı Kaplıyor) */}
        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', 
          gap: '20px', 
          maxHeight: '65vh', 
          overflowY: 'auto', 
          paddingRight: '15px',
          textAlign: 'left' 
        }}>
          {schedule && schedule.map((dayPlan, index) => (
            <div key={index} style={{ 
              backgroundColor: colors.softBeige + '30', 
              padding: '20px', 
              borderRadius: '25px', 
              border: `1px solid ${colors.softBeige}`,
              boxShadow: '0 4px 10px rgba(0,0,0,0.02)' 
            }}>
              <h4 style={{ color: colors.text, margin: '0 0 15px 0', fontSize: '18px', borderBottom: `1px solid ${colors.softBeige}`, paddingBottom: '8px' }}>
                {dayPlan.day}
              </h4>

              <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                {dayPlan.tasks && dayPlan.tasks.map((task, i) => {
                  const isDone = completedTasks[`${dayPlan.day}-${task}`];
                  return (
                    <div 
                      key={i} 
                      onClick={() => toggleTask(dayPlan.day, task)}
                      style={{ 
                        display: 'flex', 
                        alignItems: 'center', 
                        gap: '12px', 
                        backgroundColor: isDone ? colors.softGreen + '20' : colors.white, 
                        padding: '12px', 
                        borderRadius: '15px', 
                        cursor: 'pointer',
                        transition: '0.3s',
                        border: isDone ? `1px solid ${colors.softGreen}` : '1px solid #f0f0f0'
                      }}
                    >
                      <div style={{ 
                        width: '20px', 
                        height: '20px', 
                        borderRadius: '7px', 
                        border: `2px solid ${isDone ? colors.softGreen : colors.softPink}`,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        backgroundColor: isDone ? colors.softGreen : 'transparent',
                        transition: '0.2s'
                      }}>
                        {isDone && <span style={{ color: 'white', fontSize: '13px' }}>✓</span>}
                      </div>

                      <span style={{ 
                        fontSize: '14px', 
                        color: colors.text, 
                        textDecoration: isDone ? 'line-through' : 'none',
                        opacity: isDone ? 0.6 : 1
                      }}>
                        {task}
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

      </div>
    </div>
  );
};

// --- 4. SAYFA: STUDY WITH FRIENDS (YENİ EKLENEN) ---
const StudyWithFriendsPage = ({ onBack }) => {
  const [isRunning, setIsRunning] = useState(false);
  const [seconds, setSeconds] = useState(0);


  // Arkadaş Listesi State'i
  const [friends, setFriends] = useState([
    { id: 1, name: "Ayşe Yılmaz", status: "Turkish Paragraph", sec: 1935, online: true, icon: "👩🏻" },
    { id: 2, name: "Mehmet Demir", status: "On Break (Molada)", sec: 4500, online: false, icon: "👨🏻" }
  ]);

  // Yeni Arkadaş Ekleme State'leri
  const [showAddModal, setShowAddModal] = useState(false);
  const [newFriendName, setNewFriendName] = useState("");

  // 1. Sayaç Mekanizması (Benim ve Arkadaşlarımın)
  useEffect(() => {
    let interval = null;
    interval = setInterval(() => {
      // Benim sayacım
      if (isRunning) setSeconds(s => s + 1);

      // Online arkadaşların sayacı (Saniye saniye ilerlesinler)
      setFriends(prev => prev.map(f => f.online ? { ...f, sec: f.sec + 1 } : f));
    }, 1000);
    return () => clearInterval(interval);
  }, [isRunning]);

  // 2. Arkadaş Ekleme Fonksiyonu
  const handleAddFriend = async () => {
    if (newFriendName.trim() === "") return;

    try {
      // Backend'e gidip Atlas'taki o ismi soruyoruz
      const response = await fetch(`http://localhost:5001/api/users/search?name=${newFriendName}`);

      if (response.ok) {
        const foundUser = await response.json();

        // Eğer kullanıcı zaten listede yoksa ekle
        if (!friends.find(f => f.name === foundUser.name)) {
          setFriends([...friends, foundUser]);
          setShowAddModal(false);
          setNewFriendName("");
        } else {
          alert("Bu arkadaş zaten listende! 🌸");
        }
      } else {
        alert("MongoDB Atlas'ta böyle bir kullanıcı bulunamadı! 🔍");
      }
    } catch (error) {
      console.error("Bağlantı hatası:", error);
    }
  };

  return (
    <div style={{ ...commonStyles.container, position: 'relative' }}>

      {/* ARKADAŞ EKLEME MODALI (Açılır Pencere) */}
      {showAddModal && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000 }}>
          <div style={{ ...commonStyles.card, maxWidth: '400px', padding: '30px' }}>
            <h3 style={{ color: colors.softPink }}>Yeni Arkadaş Ekle 🌸</h3>
            <input 
              type="text" 
              placeholder="Arkadaşının ismi..." 
              value={newFriendName}
              onChange={(e) => setNewFriendName(e.target.value)}
              style={{ width: '100%', padding: '12px', borderRadius: '10px', border: `1px solid ${colors.softBeige}`, marginBottom: '15px', outline: 'none' }}
            />
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={handleAddFriend} style={{ ...commonStyles.button, marginTop: 0, backgroundColor: colors.softGreen }}>Ekle</button>
              <button onClick={() => setShowAddModal(false)} style={{ ...commonStyles.button, marginTop: 0, backgroundColor: '#ddd' }}>İptal</button>
            </div>
          </div>
        </div>
      )}

      <div style={{ ...commonStyles.card, maxWidth: '1000px', textAlign: 'left' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <h2 style={{ color: colors.softPink, margin: 0 }}>Live Study Room 👩🏻‍💻</h2>
          <div style={{ display: 'flex', gap: '10px' }}>
            <button onClick={() => setShowAddModal(true)} style={{ ...commonStyles.tag, backgroundColor: colors.softPink, color: 'white', border: 'none' }}>+ Arkadaş Ekle</button>
            <button onClick={onBack} style={commonStyles.tag}>← Dashboard</button>
          </div>
        </div>

        {/* ANA SAYAÇ KARTI */}
        <div style={{ backgroundColor: colors.softGreen, padding: '35px', borderRadius: '30px', color: 'white', textAlign: 'center', boxShadow: '0 8px 20px rgba(181, 228, 140, 0.4)' }}>
          <p style={{ margin: 0, opacity: 0.9 }}>Şu an çalışıyorsun: <b>Matematik - Türev</b></p>
          <h1 style={{ fontSize: '72px', margin: '15px 0', fontFamily: 'monospace' }}>{formatTime(seconds)}</h1>
          <button onClick={() => setIsRunning(!isRunning)} style={{ ...commonStyles.button, width: '200px', backgroundColor: 'white', color: colors.text, marginTop: 0 }}>
            {isRunning ? "Mola Ver (Pause)" : "Çalışmaya Başla"}
          </button>
        </div>

        {/* ŞU AN ÇALIŞANLAR LİSTESİ */}
        <h3 style={{ marginTop: '30px', color: colors.text, borderBottom: `2px solid ${colors.softBeige}`, paddingBottom: '10px' }}>Şu An Çalışanlar</h3>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '20px', marginTop: '15px' }}>
          {friends.map(f => (
            <div key={f.id} style={{ ...commonStyles.card, display: 'flex', gap: '15px', padding: '20px', maxWidth: '100%', textAlign: 'left', border: `1px solid ${colors.softBeige}` }}>
              <div style={{ fontSize: '30px', backgroundColor: colors.butterYellow, borderRadius: '50%', width: '50px', height: '50px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{f.icon}</div>
              <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <p style={{ fontWeight: 'bold', margin: 0, fontSize: '14px' }}>{f.name}</p>
                  <span style={{ fontSize: '10px', color: f.online ? colors.softGreen : '#ccc' }}>{f.online ? "● LIVE" : "● MOLA"}</span>
                </div>
                <p style={{ fontSize: '11px', color: '#aaa', margin: '2px 0' }}>{f.status}</p>
                <p style={{ fontWeight: 'bold', margin: 0, color: colors.text, fontFamily: 'monospace' }}>{formatTime(f.sec)}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};



// --- ANA UYGULAMA BİLEŞENİ ---
function App() {
  const [page, setPage] = useState(1);
  const [aiSchedule, setAiSchedule] = useState(null); // Yapay zekadan gelen veriyi sayfalar arası taşımak için

  return (
    <>
      {page === 1 && <AuthPage onNext={() => setPage(2)} />}

      {page === 2 && <OnboardingPage onNext={(scheduleData) => { 
        setAiSchedule(scheduleData); 
        setPage(3); // Program üretilince 3. sayfaya geç
      }} />}

      {page === 3 && <DashboardPage schedule={aiSchedule} onBack={() => setPage(2)} onGoToFriends={() => setPage(4)} />}

      {page === 4 && <StudyWithFriendsPage onBack={() => setPage(3)} />}  
    </>
  );
}



export default App;
